class t{constructor(){this.counters=document.querySelectorAll("[data-counter]"),this.init()}init(){if(0===this.counters.length)return;const t=new IntersectionObserver(e=>{e.forEach(e=>{e.isIntersecting&&(this.animateCounter(e.target),t.unobserve(e.target))})},{root:null,rootMargin:"0px",threshold:.3});this.counters.forEach(e=>{t.observe(e)})}animateCounter(t){const e=t.querySelector(".stat__value");if(!e)return;const n=parseFloat(e.getAttribute("data-target")),r=parseInt(e.getAttribute("data-duration"))||2e3,o=n%1!=0,a=o?(n.toString().split(".")[1]||"").length:0,i=performance.now(),s=t=>{const c=t-i,u=Math.min(c/r,1),l=1===u?1:1-Math.pow(2,-10*u),h=n*l;e.textContent=o?h.toFixed(a):Math.floor(h).toLocaleString(),u<1?requestAnimationFrame(s):e.textContent=o?n.toFixed(a):n.toLocaleString()};e.classList.add("is-counting"),requestAnimationFrame(s)}}new t;export{t as default};
